import {ActionRuntime} from '../../common/ActionRuntime';
import {Goal} from '../Goal';
import {AnimationGoalData} from '../../common/Types';


export {} // For Type definition purposes

/**
 * @internal
 */
export class AnimationGoal extends Goal {

    constructor(parent: ActionRuntime, public data: AnimationGoalData) {
        super(parent, `Playing animation of ` + (data.category) ? `category: ${data.category}` : `name: ${data.name}`, {
            priority: 8,
            maxAttempts: 1,
            criteria: data.criteria,
        });
    }
}