import {Event, EventContainer} from 'jibo-typed-events';
import {GoalProvider} from './GoalProvider';
import {State} from '../common/State';
import {GoalStatus, GoalOptions} from '../common/Types';
import {ActionRuntime} from '../common/ActionRuntime';


/**
 * @class GoalEvents
 * @memberof jibo.action.goal
 * @property {Event} selected - Goal has been selected
 * @property {Event} culled - Goal has been culled
 * @property {Event} achieved - Goal has been achieved
 * @property {Event} failed - Goal has failed
 * @property {Event} removed - Goal has been removed from list
 */
export class GoalEvents extends EventContainer {

    selected = new Event('Selected');
    culled = new Event('Culled');
    achieved = new Event('Achieved');
    failed = new Event('Failed');
    removed = new Event('Removed');

    constructor() {
        super();
    }
}

/**
 * The core representation for a goal in the action system. This class
 * is subclassed for various specific types of goals.
 * @class Goal
 * @memberof jibo.action.goal
 */
export class Goal {

    /**
     * Various goal events
     * @name jibo.action.goal.Goal#events
     * @type jibo.action.goal.GoalEvents
     */
    public events = new GoalEvents();

    /**
     * Current status of goal
     * @name jibo.action.goal.Goal#status
     * @type jibo.action.types#GoalStatus
     * @readonly
     */
    public status: GoalStatus = GoalStatus.INITIAL;

    public provider: GoalProvider;
    public attempts = 0;
    public created: Date;

    /**
     * @internal
     */
    options: GoalOptions;

    /**
     * @internal
     */
    protected parent: ActionRuntime;

    /**
     * @internal
     */
    constructor(parent: ActionRuntime, public name: string, options: GoalOptions = {priority: 5}) {
        this.parent = parent;
        this.options = options;
        if (options.maxAttempts === undefined) {
            options.maxAttempts = 3;
        }
        this.created = parent.dateProvider.getDate();
    }

    /**
     * Sets the appropriate status of this goal and emits events as appropriate
     * @param {GoalStatus} status
     * @internal
     */
    setStatus(status: GoalStatus) {
        this.status = status;
        switch (status) {
            case GoalStatus.CULLED:
                this.events.culled.emit();
                break;
            case GoalStatus.ACHIEVED:
                this.events.achieved.emit();
                break;
            case GoalStatus.SELECTED:
                this.events.selected.emit();
                break;
            case GoalStatus.FAILED:
                this.events.failed.emit();
                break;
        }
    }

    /**
     * Whether this goal is eligible given the state
     * @param {State} state
     * @return {boolean}
     * @internal
     */
    isEligible(state: State): boolean {
        if (this.options.criteria) {
            const criteria = this.options.criteria;
            // Start time eligible
            if (criteria.startTime && state.time < criteria.startTime) {
                return false;
            }
            // End time eligible
            if (criteria.endTime && state.time > criteria.endTime) {
                return false;
            }
            // Current skill eligible
            if (criteria.currentSkill && state.skillName !== criteria.currentSkill) {
                return false;
            }
            // Person present eligible
            if (criteria.personPresent) {
                if (state.users.map(u => u.id).indexOf(criteria.personPresent) === -1) {
                    return false;
                }
            }
        }
        return true;
    }

    /**
     * Whether this goal can be removed from a goal set since
     * its context will never be achieved
     * @param {State} state
     * @internal
     */
    canBeCulled(state: State): boolean {
        if (this.options.criteria) {
            const criteria = this.options.criteria;
            return (criteria.endTime && state.time > criteria.endTime);
        }
        return false;
    }
}
