import {State} from '../common/State';
import {DriveName} from '../motivation/MotivationSystem';
import {ActionResult, ActionStatus} from '../common/Types';


/**
 * The core representation of an action in the action system. This class
 * is subclassed for various specific types of actions.
 * @class Action
 * @memberof jibo.action.action
 */
export class Action {

    /**
     * Current status of the action
     * @name jibo.action.action.Action#status
     * @type jibo.action.types#ActionStatus
     * @readonly
     */
    public status = ActionStatus.NOT_RUNNING;

    /**
     * Describes to what extent this action satisfies
     * each type of drive
     * @type {number[]}
     * @private
     */
    private _driveEffects: number[] = [];

    private _runPromiseResolve: (x: ActionResult)=>void;

    /**
     * Constructs an action object
     * @param {string} name - Name of action
     * @param {Object} driveEffects - String to number map of how this action affects
     * the motivational drives
     * @internal
     */
    constructor(public name: string, driveEffects: {[x: string]: number} = {}) {
        Object.keys(driveEffects).forEach(key => {
            const driveIndex = DriveName[key];
            if (driveIndex === undefined) {
                throw Error(`Invalid drive name '${key}'`);
            }
            this._driveEffects[driveIndex] = driveEffects[key];
        });
    }

    /**
     * Cancels ongoing action (resolves promise with CANCELED status)
     * @internal
     */
    public async cancel(): Promise<any> {
        if (this._runPromiseResolve) {
            this._runPromiseResolve(ActionResult.CANCELED);
            return this.cancelInternal();
        }
    }

    /**
     * Should be overridden by actions that want to respond to canceling
     * @internal
     */
    protected async cancelInternal(): Promise<any> {
        return Promise.resolve();
    }

    /**
     * How much this action will affect any given drive
     * @param {DriveName} drive - The name of the drive
     * @return {number}
     * @internal
     */
    getDriveEffect(drive: DriveName) {
        return this._driveEffects[drive] || 0;
    }

    /**
     * Runs this action
     * @return {Promise<ActionResult>}
     * @internal
     */
    public async run(): Promise<ActionResult> {
        this.status = ActionStatus.RUNNING;
        return new Promise<ActionResult>((resolve, reject) => {
            this._runPromiseResolve = resolve;
            this.runInternal()
                .then(result => {
                    this._runPromiseResolve = null;
                    this.status = ActionStatus.NOT_RUNNING;
                    resolve(result);
                }).catch(e => {
                this._runPromiseResolve = null;
                this.status = ActionStatus.NOT_RUNNING;
                reject(e);
            });
        });
    }

    /**
     * This method should be overridden by subclasses and provide
     * actual action run logic
     * @return {Promise<ActionResult>}
     * @internal
     */
    protected async runInternal(): Promise<ActionResult> {
        return Promise.resolve(ActionResult.SUCCEEDED);
    }

    /**
     * Determines if this action is eligible in a given state
     * Should be overridden by subclasses
     * @param {object} state
     * @return {boolean}
     * @internal
     */
    isEligible(state: State): boolean {
        return true;
    }
}
