/**
 * @internal
 */
export class TimeConversion {

    static msToSeconds(ms: number) {
        return ms / (1000);
    }

    static msToMinutes(ms: number) {
        return ms / (60 * 1000);
    }

    static msToHours(ms: number) {
        return ms / (60 * 60 * 1000);
    }
}
