import {Goal} from './Goal';
import {State} from '../common/State';
import {ActionRuntime} from '../common/ActionRuntime';
import {HJGoal} from "./goals/HJGoal";


export {} // For Type definition purposes

/**
 * @internal
 */
export class GoalSet {

    private goals: Goal[] = [];

    constructor(public parent: ActionRuntime) {
    }

    /**
     * Add a goal to the goal list
     * @param {Goal} goal
     * @returns {Goal} Either the same goal as was provided or
     * another existing goal from the list if there should only be one goal of that kind
     */
    addGoal(goal: Goal): Goal {
        let selected = goal;
        if (goal instanceof HJGoal) {
            for (let i=0; i<this.goals.length; i++) {
                if (this.goals[i] instanceof HJGoal) {
                    selected = this.goals[i];
                    break;
                }
            }
        }
        if (selected === goal) {
            this.goals.push(selected);
            this.parent.events.goalAdded.emit(selected);
        }
        return selected;
    }

    /**
     * Chooses best goal to achieve and removes it from list
     * TODO: Improve this selection
     */
    chooseGoal(state: State): Goal {

        const eligibleGoals = [];
        let nonCulled = [];

        // Cull all out-of-date goals
        for (let goal of this.goals) {
            if (goal.isEligible(state)) {
                eligibleGoals.push(goal);
                nonCulled.push(goal);
            } else if (goal.canBeCulled(state)) {
                // TODO consider race conditions
                goal.events.culled.emit();
                this.parent.events.goalCulled.emit(goal);
            } else {
                nonCulled.push(goal);
            }
        }
        this.goals = nonCulled;

        // Pick highest priority goal from eligible goals
        if (eligibleGoals.length) {
            // Sort in descending order
            eligibleGoals.sort((a: Goal, b: Goal) => {
                return b.options.priority - a.options.priority;
            });
            return eligibleGoals[0];
        }
        else {
            return null;
        }
    }

    /**
     * Removes goal from lists
     * @param goal
     */
    removeGoal(goal: Goal) {
        let index = this.goals.indexOf(goal);
        if (index > -1) {
            this.goals.splice(index, 1);
            goal.events.removed.emit();
        }
        else {
            this.parent.log.warn(`Trying to remove goal but didn't find it in goal list`);
        }
    }
}
