import {ActionRuntime} from '../common/ActionRuntime';
import {Goal} from './Goal';
import {GoalStatus} from '../common/Types';


export class GoalProvider {

    /**
     * @internal
     */
    parent: ActionRuntime;

    /**
     * @internal
     */
    constructor(parent: ActionRuntime, public name: string) {
        this.parent = parent;
    }

    /**
     * Called on this provider when it should provide a goal
     * Puts goal in goal set and emits goalProvided event
     * @param {Goal} goal
     * @returns {Goal} Either the same goal as was provided or
     * another existing goal from the list if there should only be one goal of that kind
     * @internal
     */
    public provideGoal(goal: Goal): Goal {
        goal.provider = this;
        goal.setStatus(GoalStatus.PENDING);
        return this.parent.goals.addGoal(goal);
    }
}