import {ActionRuntime} from '../../common/ActionRuntime';
import {GoalProvider} from '../GoalProvider';
import {HJGoal} from '../goals/HJGoal';


export {} // For Type definition purposes

/**
 * @internal
 */
export class HJGoalProvider extends GoalProvider {

    private processAudioFrameBind = this.processAudioFrame.bind(this);
    private lastHJId = -9999;

    constructor(parent: ActionRuntime) {
        super(parent, 'Hey Jibo Goal Provider');
    }

    init() {
        this.parent.jibo.lps.events.audio.on(this.processAudioFrameBind);
    }

    dispose() {
        this.parent.jibo.lps.events.audio.removeListener(this.processAudioFrameBind);
    }

    /**
     * Processes an LPS audio data frame
     * @param data
     */
    private processAudioFrame(data) {
        for (let aei = 0; aei < data.entities.length; aei++) {
            const entity: any = data.entities[aei];
            // If the entity type is a wakeword
            if (entity.type === 1) {
                const id = entity.id;
                // If the timestamp is different from the last record
                if (id !== this.lastHJId) {
                    this.provideGoal(new HJGoal(this.parent, entity));
                }
                this.lastHJId = id;
            }
        }
    }
}
