import {Action} from '../Action';
import {ActionRuntime} from '../../common/ActionRuntime';
import {ActionResult, AnimationGoalData} from '../../common/Types';
import * as _ from 'lodash';

// Only importing type definition
import JiboImport = require('../../../../jibo'); // NOTE: only for type declaration, not runtime dependency
type Animation = JiboImport.animDB.Animation;

/**
 * @internal
 */
export class AnimationAction extends Action {

    private instance: any;

    constructor(public parent: ActionRuntime, private data: AnimationGoalData) {
        super(`Animation Action`);
    }

    protected async runInternal(): Promise<ActionResult> {
        let anim: Animation;
        if (this.data.category) {
            const animRes = this.parent.jibo.animDB.query({category: this.data.category});
            if (!animRes || animRes.matching.length === 0) {
                this.parent.log.error(`Couldn't find animation of category '${this.data.category}'`);
                return ActionResult.FAILED;
            }
            anim = _.sample(animRes.matching);
        } else if (this.data.name) {
            anim = this.parent.jibo.animDB.getAnimByName(this.data.name);
            if (!anim) {
                this.parent.log.error(`No animation of name '${this.data.name}' found`);
                return ActionResult.FAILED;
            }
        } else {
            this.parent.log.error(`Invalid anim data`);
            return ActionResult.FAILED;
        }

        const animation = await anim.createFromConfig();
        await animation.play({
            handleAnimation: (animation) => {
                this.instance = animation;
            }
        });

        this.instance = null;
        return ActionResult.SUCCEEDED;
    }

    protected async cancelInternal(): Promise<any> {
        if (this.instance) {
            this.instance.stop();
        }
    }
}

export {} // Needed for type definitions