import {Goal} from '../Goal';
import {ActionRuntime} from '../../common/ActionRuntime';
import {SSWGoalData} from '../../common/Types';


export {} // For Type definition purposes

/**
 * @internal
 */
export class SSWGoal extends Goal {

    constructor(parent: ActionRuntime, public data: SSWGoalData) {
        super(parent, `Scheduled Skill Launch: '${data.skillName}'`, {
            priority: 9,
            maxAttempts: 1,
            criteria: data.criteria,
        });
    }
}