import {ActionRuntime} from '../../common/ActionRuntime';
import {GoalProvider} from '../GoalProvider';
import {HJOnlyGoal} from '../goals/HJOnlyGoal';
import {SkillNames} from '../../common/Utils';


export {} // For Type definition purposes

/**
 * @internal
 */
export class HJOnlyGoalProvider extends GoalProvider {

    private handleHJOnlyBind = this.handleHJOnly.bind(this);

    constructor(parent: ActionRuntime) {
        super(parent, 'Hey Jibo Only Goal Provider');
    }

    init() {
        this.parent.jibo.gl.events.hjOnly.on(this.handleHJOnlyBind);
    }

    dispose() {
        this.parent.jibo.gl.events.hjOnly.removeListener(this.handleHJOnlyBind);
    }

    handleHJOnly() {
        const state = this.parent.createState();
        if (state.skillName === SkillNames.IDLE) {
            this.provideGoal(new HJOnlyGoal(this.parent));
        }
    }
}
