import {Goal} from '../goal/Goal';
import {GoalProvider} from '../goal/GoalProvider';
import {Drive} from './Drive';
import {ActionRuntime} from '../common/ActionRuntime';


export {} // For Type definition purposes

/**
 * @internal
 */
export enum DriveName {
    PLAYFUL = 0,
    SOCIAL = 1,
    CURIOUS = 2
}


/**
 * @internal
 */
export class MotivationSystem {

    public drives = [
        new Drive('Playful'),
        new Drive('Social'),
        new Drive('Curious'),
    ];

    public goalProvider: GoalProvider;

    private activeMotivationGoal: Goal;

    constructor(private parent: ActionRuntime) {
        this.goalProvider = new GoalProvider(parent, 'Motivation');
    }

    /**
     * Returns the proper motivational drive by name
     * @param name
     * @return {Drive}
     */
    public getDrive(name: DriveName): Drive {
        return this.drives[name];
    }

    /**
     * Update all motivational drives and create a goal if needed
     */
    public update() {
        for (let drive of this.drives) {
            drive.update();

            // If we don't have an active motivational goal then we create one
            if (!this.activeMotivationGoal && drive.value >= drive.threshold) {
                this.activeMotivationGoal = new Goal(this.parent, 'Motivation goal', {priority: 5});
                // When this goal gets removed from the goal list, we invalidate it here
                this.activeMotivationGoal.events.removed.on(() => {
                    this.activeMotivationGoal = null;
                });
                // And now we provide the goal to the goal list
                this.goalProvider.provideGoal(this.activeMotivationGoal);
            }
        }
    }
}