import {ActionRuntime} from '../../common/ActionRuntime';
import {GoalProvider} from '../GoalProvider';
import {SSWGoal} from '../goals/SSWGoal';


export {} // For Type definition purposes

/**
 * @internal
 */
export class SSWGoalProvider extends GoalProvider {

    private handleRelaunchBind = this.handleRelaunch.bind(this);

    constructor(parent: ActionRuntime) {
        super(parent, 'Skill SwitchGoal Provider');
    }

    init() {
        this.parent.jibo.gl.on('relaunch', this.handleRelaunchBind);
    }

    dispose() {
        this.parent.jibo.gl.removeListener('relaunch', this.handleRelaunchBind);
    }

    private handleRelaunch(result: any) {
        const skillName = result.NLParse.skill;
        this.provideGoal(new SSWGoal(this.parent, {
            skillName,
            skillOptions: result
        }));
    }
}