import {Action} from '../Action';
import {State} from '../../common/State';
import {ActionRuntime} from '../../common/ActionRuntime';
import {Point3, ActionResult} from '../../common/Types';
import {PromiseUtils} from 'jibo-cai-utils';

// Require all the flows to make sure they browserify
const F_PERKUP = require('../../flows/x5/perkup.flow');
const F_SCAN = require('../../flows/x5/scan.flow');
const F_GIVE_UP = require('../../flows/x5/give-up.flow');
const F_SUCCESS = [
    require('../../flows/x5/success-01.flow'),
    require('../../flows/x5/success-02.flow'),
    require('../../flows/x5/success-03.flow'),
];
const F_DISAPPOINTMENT = [
    require('../../flows/x5/disappointment-01.flow'),
    require('../../flows/x5/disappointment-02.flow'),
];
const F_NO_FACE_FOUND = require('../../flows/x5/no-face-found.flow');
const F_ENGAGED = require('../../flows/x5/engaged.flow');
const F_DISENGAGED = require('../../flows/x5/disengaged.flow');
const F_END_LISTEN = require('../../flows/x5/end-listening.flow');

const N_ATTEMPTS = 4;

/**
 * @internal
 */
export class HJOrientWithCharacter extends Action {

    reactions = new Reactions(this.parent);

    /**
     * Constructs an action object
     * @param {ActionRuntime} parent - Behavior runtime parent
     * @param {Point3} initialLocation - Initial lookat location
     */
    constructor(public parent: ActionRuntime, private initialLocation: Point3) {
        super('HJOrientWithCharacter Action');
    }

    /**
     * Should be overridden by actions that want to respond to canceling
     */
    protected async cancelInternal(): Promise<any> {
        return Promise.resolve();
    }

    /**
     * This method should be overridden by subclasses and provide
     * actual action run logic
     * @return {HJGoal} goal - The goal to solve
     * @return {Promise<ActionResult>}
     */
    protected async runInternal(): Promise<ActionResult> {
        this.parent.log.log(`Starting HJOrientWithCharacter action`);
        const jibo = this.parent.jibo;

        // const embodiedListen = this.parent.options.embodiedListen;
        const oldAttentionMode = jibo.attention.getMode();
        jibo.attention.setMode(jibo.attention.Mode.COMMAND);

        const result = await this.runInternal2();
        this.parent.events.oriented.emit();

        await this.reactions.afterListening();

        jibo.attention.setMode(oldAttentionMode);
        return result;
    }

    protected async runInternal2(): Promise<ActionResult> {
        const attention = this.parent.jibo.attention;
        // do a perk-up reaction
        await this.reactions.perkUp();
        //console.log('skipped perkUp reaction');
        // make call to attention system for orient to position
        this.parent.log.log(`calling attendToTarget. position: `, this.initialLocation);
        try {
            const pos = this.initialLocation;
            await attention.attendToTarget([pos.x, pos.y, Math.max(0.7, pos.z)], null).promise;
        } catch (e) {
            this.parent.log.error('attendToTarget barfed: ', e);
        }
        this.parent.log.log(`attendToTarget resolved`);
        // make call to attention system to check if we (~immediately) have a face
        let awaitFace = attention.awaitFace(0);
        this.parent.log.log('awaiting resolution of awaitFace promise');
        let haveFace = await awaitFace.promise;
        this.parent.log.log('awaitFace promise resolved');
        if (haveFace.status === 'SUCCEEDED') {
            // if so, center on face, do a success reaction, then done
            this.parent.log.log('attending to target');
            await attention.attendToTarget(haveFace.position, null).promise;
            await this.reactions.engaged();
            this.parent.log.log('returning with success');
            return ActionResult.SUCCEEDED;
        } else {
            let attempts = 0;
            // keep this guy around for the duration of a search of many locations:
            let searchIterator = attention.getSearchIterator();
            // do a few times:
            while (attempts < N_ATTEMPTS) {
                // if not, make call to attention system to look for face
                // in parallel, launch stationary-body looking animation to mask perceptual processing time
                const scanpr = this.reactions.scan();
                //console.log('scan temporarily removed');
                // ^ that's gonna need to be interruptible, we'll interrupt it when awaitFace resolves
                let awaitFace = attention.awaitFace(5); // two seconds timeout
                this.parent.log.log('awaiting resolution of awaitFace promise (5 sec timeout)');
                let haveFace = await awaitFace.promise;
                this.parent.log.log('awaitFace promise resolved');
                // regardless of status, we need to stop the masking animation here
                this.reactions.stop();
                await scanpr;
                if (haveFace.status === attention.ResultStatus.SUCCEEDED) {
                    // if face found, center on face, do success reaction, then done
                    this.parent.log.log('attending to target');
                    await attention.attendToTarget(haveFace.position, null).promise;
                    // success reaction
                    await this.reactions.success(attempts);
                    await this.reactions.engaged();
                    // This turns on the listening eye and engaged listening state
                    this.parent.log.log('returning with success');
                    return ActionResult.SUCCEEDED;
                } else {
                    // no face.
                    // disappointed reaction
                    await this.reactions.disappointment(attempts + 1);
                    if (!(attempts === N_ATTEMPTS - 1)) {
                        // select a new location
                        this.parent.log.log('getting next target');
                        const target = searchIterator.nextTarget();
                        this.parent.log.log('attending to target');
                        await attention.attendToTarget(target, null).promise;
                    }
                }
                attempts++;
            }
            // if we finish the while, give up with give up reaction
            // give up reaction
            await this.reactions.giveUp();
            this.parent.log.log('returning with failure');
            return ActionResult.FAILED;
        }
    }

    /**
     * Determines if this action is eligible in a given state
     * Should be overridden by subclasses
     * @param {object} state
     * @return {boolean}
     */
    isEligible(state: State): boolean {
        return true;
    }

    async doFlow(flowname: string): Promise<any> {
        this.parent.log.log(`pretending to play ${flowname}`);
        return Promise.resolve();
    }
}


/**
 * @internal
 */
export class Reactions {

    currentFlow: any;

    constructor(private parent: ActionRuntime) {
    }

    async test() {
        await this.perkUp();

        setTimeout(() => {
            this.parent.log.log('Stopping scanning');
            this.stop();
        }, 5000);
        await this.scan();

        await this.giveUp();
        await this.success(1);
        await this.success(2);
        await this.success(3);
        await this.disappointment(1);
        await this.disappointment(2);
        await this.noFaceFound();
        await this.engaged();
        await this.disengaged();
    }

    async stop() {
        if (this.currentFlow) {
            return this.currentFlow.stop();
        }
    }

    async perkUp() {
        return this.doFlow('perkup', F_PERKUP);
    }

    async scan() {
        return this.doFlow('scan', F_SCAN);
    }

    async giveUp() {
        return this.doFlow('give-up', F_GIVE_UP);
    }

    async noFaceFound() {
        return this.doFlow('no-face-found', F_NO_FACE_FOUND);
    }

    async engaged() {
        return this.doFlow('engaged', F_ENGAGED);
    }

    async disengaged() {
        return this.doFlow('disengaged', F_DISENGAGED);
    }

    async afterListening() {
        return this.doFlow('end-listening', F_END_LISTEN);
    }

    async success(loop: number) {
        loop = Math.min(3, Math.max(1, loop));
        return this.doFlow(`success-0${loop}`, F_SUCCESS[loop - 1]);
    }

    async disappointment(loop: number) {
        loop = Math.min(2, Math.max(1, loop));
        return this.doFlow(`disappointment-0${loop}`, F_DISAPPOINTMENT[loop - 1]);
    }

    async doFlow(name: string, flow: any): Promise<any> {
        this.parent.log.log(`Running reaction flow: ${name}`);

        if (this.currentFlow) {
            this.parent.log.log(`Stopping previous flow`);
            await this.currentFlow.stop();
        }

        return PromiseUtils.promisify<any>(h => {
            if (!flow) {
                throw Error(`Can't start flow '${name}' since flow is falsey`);
            }
            this.currentFlow = this.parent.jibo.flow.run(flow, {}, h);
        }).then(() => {
            this.parent.log.log(`Done with reaction flow: ${name}`);
            this.currentFlow = null;
        }).catch(e => {
            this.currentFlow = null;
            throw e;
        });
    }
}

export {} // Needed for type definitions