import {ActionRuntime} from './common/ActionRuntime';
import {ActionEvents} from './common/ActionEvents';
import * as action_ns from './action';
import * as types from './common/Types';
import * as goal_ns from './goal';

/**
 * @namespace jibo.action.goal
 */
declare namespace goal {
    export type GoalEvents = goal_ns.GoalEvents;
    export type Goal = goal_ns.Goal;
}

/**
 * @namespace jibo.action.action
 */
declare namespace action {
    export type Action = action_ns.Action;
}

/*
 * Export namespaces
 */
export {
    types,
    goal,
    action,
}

/*
 * Private variables
 */

/**
 * The instance of the runtime. We expose it on the API just for
 * testing and special circumstances. Not meant to be accessed for standard use.
 * @type {jibo.action.ActionRuntime}
 * @internal
 * @private
 */
export let _runtime: ActionRuntime;

/*
 * Public API variables
 */

/**
 * Various events emitted by the action system.
 * @name jibo.action#events
 * @type {jibo.action.ActionEvents}
 */
export let events: ActionEvents;

/*
 * Public API methods
 */

/**
 * Initializes the action system.
 * @method jibo.action#init
 * @param {jibo.action.types.InitOptions} options - Constructor options.
 * @returns {Promise<void>} A promise that is resolved when the Action runtime has been initializd
 */
export function init(options: types.InitOptions): Promise<void> {
    _runtime = new ActionRuntime();
    events = _runtime.events;
    return _runtime.init(options);
}

/**
 * Tells the action system what skill is currently active.
 * @method jibo.action#setCurrentSkill
 * @param {String} skillName - Name of the current skill.
 */
export function setCurrentSkill(skillName: string): void {
    _runtime.currentSkillName = skillName;
}

/**
 * Sets the skill switch handler.
 * @method jibo.action#setSkillSwitchHandler
 * @param {jibo.action.types.SkillSwitchHandler} skillSwitcher - A callback method for handling skill.
 * switch requests from the action system
 */
export function setSkillSwitchHandler(skillSwitcher: types.SkillSwitchHandler): void {
    _runtime.skillSwitcher = skillSwitcher;
}

/**
 * Retrieves the goal that is currently being retrieved.
 * @method jibo.action#getCurrentGoal
 * @return {jibo.action.goal.Goal} Current goal or undefined if none is active.
 */
export function getCurrentGoal(): goal.Goal {
    return _runtime.current ? _runtime.current.goal : null;
}

/**
 * Retrieves the current action that the action system is taking.
 * @method jibo.action#getCurrentAction
 * @return {jibo.action.action.Action} Current action or undefined if none is being taken.
 */
export function getCurrentAction(): action.Action {
    return _runtime.current ? _runtime.current.action : null;
}

/**
 * Creates and adds a Skill Switch Goal.
 * @method jibo.action#addSkillSwitchGoal
 * @param {jibo.action.types#SSWGoalData} data - The required data to form the goal.
 * @return {jibo.action.goal.Goal} The new goal or an existing goal of the same type.
 */
export function addSkillSwitchGoal(data: types.SSWGoalData): goal.Goal {
    const goal = new goal_ns.goals.SSWGoal(_runtime, data);
    return _runtime.goals.addGoal(goal);
}

/**
 * Creates and adds a Play Animation goal.
 * @method jibo.action#addPlayAnimationGoal
 * @param {jibo.action.types#AnimationGoalData} data - The required data to form the goal.
 * @return {jibo.action.goal.Goal} The new goal or an existing goal of the same type.
 */
export function addPlayAnimationGoal(data: types.AnimationGoalData): goal.Goal {
    const goal = new goal_ns.goals.AnimationGoal(_runtime, data);
    return _runtime.goals.addGoal(goal);
}
