import {Action} from './Action';
import {Goal} from '../goal/Goal';
import {ActionRuntime} from '../common/ActionRuntime';
import {ActionResult, GoalStatus} from '../common/Types';


export {} // For type definition purposes

/**
 * @description
 * Represents a goal and an action
 * to accomplish the goal.
 * @internal
 */
export class GoalDrivenAction {

    public currentRunPromise: Promise<ActionResult> = null;

    constructor(public goal: Goal, public action: Action, private parent: ActionRuntime) {
    }

    /**
     * Takes the action that accomplishes the goal
     * and updates the status of the goal accordingly
     * @return {Promise<ActionResult>}
     */
    public async run(): Promise<ActionResult> {
        this.parent.log.log(`Taking action: '${this.action.name}' to achieve goal '${this.goal.name}'`);
        this.goal.attempts++;
        this.currentRunPromise = this.action.run()
            .then(result => {
                this.parent.log.log(`Completed action: '${this.action.name}' with result: '${result}'`);
                this.currentRunPromise = null;
                switch (result) {
                    case ActionResult.SUCCEEDED:
                        this.goal.setStatus(GoalStatus.ACHIEVED);
                        this.parent.goals.removeGoal(this.goal);
                        break;
                    case ActionResult.FAILED:
                        this.goal.setStatus(GoalStatus.FAILED);
                        if (this.goal.attempts >= this.goal.options.maxAttempts) {
                            this.parent.goals.removeGoal(this.goal);
                        }
                        break;
                    case ActionResult.CANCELED:
                        this.goal.setStatus(GoalStatus.PENDING);
                        if (this.goal.attempts >= this.goal.options.maxAttempts) {
                            this.parent.goals.removeGoal(this.goal);
                        }
                        break;
                }
                return result;
            }).catch(error => {
                this.parent.log.error(`ActionError: `, error);
                this.currentRunPromise = null;
                this.goal.setStatus(GoalStatus.FAILED);
                if (this.goal.attempts >= this.goal.options.maxAttempts) {
                    this.parent.goals.removeGoal(this.goal);
                }
                return ActionResult.FAILED;
            });
        return this.currentRunPromise;
    }
}
