import * as _ from 'lodash';
import {Action} from './Action';
import {State} from '../common/State';
import {Goal} from '../goal/Goal';
import {ActionRuntime} from '../common/ActionRuntime';
import {ActionPolicy} from "./policies/ActionPolicy";
import {BasicPolicy} from "./policies/BasicPolicy";

export {} // For type definition purposes

/**
 * @internal
 */
export class ActionSystem {

    private actions: Action[] = [];
    private policy: ActionPolicy = new BasicPolicy(this.parent);

    constructor(private parent: ActionRuntime) {
    }

    /**
     * Adds an action to the action system
     * @param action
     */
    public addAction(action: Action) {
        this.actions.push(action);
    }

    /**
     * Chooses the actions to be taken in a state given a set of goals
     */
    public chooseAction(state: State, goal: Goal, eligibleActions?: Action[]): Action {
        // If this goal has a suggested action to take
        const suggestedActionProvider = goal.options.action;
        if (suggestedActionProvider) {
            const suggestedAction = suggestedActionProvider();
            if (suggestedAction.isEligible(state)) {
                return suggestedAction;
            }
        }

        // Otherwise we choose an action based on installed policy
        const action = this.policy.selectAction(goal, state);

        if (action) {
            return action;
        }

        // Lastly we select from the eligible actions
        // TODO This has to be thought though better, what actions should be available here (SSW for example?)
        if (!eligibleActions) {
            eligibleActions = this.actions.filter(a => a.isEligible(state));
        }

        return _.sample(eligibleActions);
    }
}
