import {ActionRuntime} from '../../common/ActionRuntime';
import {Goal} from '../Goal';


export {} // For Type definition purposes

/**
 * @internal
 */
export interface AudioFrame {
    entities: AudioEntity[];
}

/**
 * @internal
 */
export interface AudioEntity {
    id: string;
    type: number;
    position: {
        x: number;
        y: number;
        z: number;
    };
    ts: [number, number];
}

/**
 * @internal
 */
export class HJGoal extends Goal {

    constructor(parent: ActionRuntime, public entity: AudioEntity) {
        super(parent, 'Hey Jibo', {
            priority: 10,
            maxAttempts: 1,
        });
    }
}