/**
 * @namespace jibo.action.types
 */

import {Action} from '../action/Action';
import {Goal} from '../goal/Goal';

/**
 * Enum of the current status of a goal
 * @typedef jibo.action.types#GoalStatus
 * @property {String} INITIAL
 * @property {String} ACHIEVED
 * @property {String} CULLED
 * @property {String} PENDING
 * @property {String} SELECTED
 * @property {String} FAILED
 */
export type GoalStatus = 'INITIAL'|'ACHIEVED'|'CULLED'|'PENDING'|'SELECTED'|'FAILED';
export namespace GoalStatus {
    export const INITIAL: GoalStatus = 'INITIAL';
    export const ACHIEVED: GoalStatus = 'ACHIEVED';
    export const CULLED: GoalStatus = 'CULLED';
    export const PENDING: GoalStatus = 'PENDING';
    export const SELECTED: GoalStatus = 'SELECTED';
    export const FAILED: GoalStatus = 'FAILED';
}

/**
 * Enum of the outcome of an action
 * @typedef jibo.action.types#ActionResult
 * @property {String} SUCCEEDED
 * @property {String} FAILED
 * @property {String} CANCELED
 */
export type ActionResult = 'SUCCEEDED'|'FAILED'|'CANCELED';
export namespace ActionResult {
    export const SUCCEEDED: ActionResult = 'SUCCEEDED';
    export const FAILED: ActionResult = 'FAILED';
    export const CANCELED: ActionResult = 'CANCELED';
}

/**
 * Enum of current status of an action
 * @typedef jibo.action.types#ActionStatus
 * @property {String} RUNNING
 * @property {String} NOT_RUNNING
 */
export type ActionStatus = 'RUNNING'|'NOT_RUNNING';
export namespace ActionStatus {
    export const RUNNING: ActionStatus = 'RUNNING';
    export const NOT_RUNNING: ActionStatus = 'NOT_RUNNING';
}

// * @memberof jibo.action.types

/**
 * Enum of skill switch outcomes
 * @typedef jibo.action.types#Status
 * @property {String} SUCCEEDED
 * @property {String} FAILED
 */
export type Status = 'SUCCEEDED' | 'FAILED';
export namespace Status {
    export const SUCCEEDED: Status = 'SUCCEEDED';
    export const FAILED: Status = 'FAILED';
}

/**
 * @internal
 */
export type Callback<T> = (err?: string|Error, data?: T) => void;

/**
 * This callback is displayed as part of the Requester class.
 * @memberof jibo.action.types
 * @callback SkillSwitchHandler
 * @param {String} skillName - Name of skill to switch to
 * @param {Object} skillData - Data to provide to launched skill
 * @return {Promise.<jibo.action.types#Status>}
 */
export type SkillSwitchHandler = (skillName: string, skillData: any) => Promise<Status>;


/**
 * Constructor options for the Jibo actions system
 * @memberof jibo.action.types
 * @typedef InitOptions
 * @property {Jibo} jibo - The Jibo runtime
 * @property {boolean} [autoUpdate=true] - Whether action system should create its own update loop
 */
export interface InitOptions {
    jibo: any;
    autoUpdate?: any;
}

/**
 * @internal
 */
export interface GoalOptions {
    priority: number;
    maxAttempts?: number;
    action?: ActionProvider;
    criteria?: Criteria;
}

/**
 * @internal
 */
export interface Point3 {
    x: number;
    y: number;
    z: number;
}

/**
 * Selection criteria for a goal. If a parameter in this interface is provided, then
 * the criteria defined by that parameter is enforced for a goal to be eligible
 * @typedef jibo.action.types#Criteria
 * @property {Number} [startTime] - The earliest time a goal can be selected
 * @property {Number} [endTime] - The latest time a goal can be selected
 * @property {String} [personPresent] - The id of the person that needs to be present
 * @property {String} [currentSkill] - The name of the current skill that needs to be active
 */
export interface Criteria {
    startTime?: number;
    endTime?: number;
    personPresent?: string;
    currentSkill?: string;
}

/**
 * Skill switch goal data
 * @typedef jibo.action.types#SSWGoalData
 * @property {String} skillName - Name of skill to switch into
 * @property {Object} skillOptions - Data to provide to launched skill
 * @property {jibo.action.types#Criteria} [criteria] - Selection criteria for goal
 */
export interface SSWGoalData  {
    skillName: string;
    skillOptions: any;
    criteria?: Criteria;
}

/**
 * Animation goal data
 * @typedef jibo.action.types#AnimationGoalData
 * @property {String} [category] - Name of the desired animation category
 * @property {String} [name] - Name of the desired animation
 * @property {jibo.action.types#Criteria} [criteria] - Selection criteria for goal
 */
export interface AnimationGoalData {
    category: string;
    name: string;
    criteria?: Criteria;
}

/**
 * @internal
 */
export type ActionProvider = (goal?: Goal) => Action;
