import {Action} from '../Action';
import {Point3, ActionResult} from '../../common/Types';
import {ActionRuntime} from '../../common/ActionRuntime';

/**
 * @internal
 */
export class BasicLookat extends Action {

    /**
     * Constructs an action object
     * @param {ActionRuntime} parent - Behavior runtime parent
     * @param {Point3} location - Look at location
     */
    constructor(public parent: ActionRuntime, private location: Point3) {
        super('Basic Lookat Action');
    }

    /**
     * Should be overridden by actions that want to respond to canceling
     */
    protected async cancelInternal(): Promise<any> {
        return Promise.resolve();
    }

    /**
     * This method should be overridden by subclasses and provide
     * actual action run logic
     * @return {Promise<ActionResult>}
     */
    protected async runInternal(): Promise<ActionResult> {
        const attention = this.parent.jibo.attention;

        // const embodiedListen = this.parent.options.embodiedListen;
        const oldAttentionMode = attention.getMode();
        attention.setMode(attention.Mode.COMMAND);
        let result: ActionResult;
        try {
            const pos = this.location;
            // TODO grab the cancel method hook and make available in cancelInternal above
            await attention.attendToTarget([pos.x, pos.y, Math.max(0.7, pos.z)], null).promise;
            result = ActionResult.SUCCEEDED;
        } catch (e) {
            this.parent.log.error('attention.attendToTarget error: ', e);
            result = ActionResult.FAILED;
        }
        this.parent.events.oriented.emit();

        attention.setMode(oldAttentionMode);
        return result;
    }
}

export {} // Needed for type definitions