import {GoalSet} from '../goal/GoalSet';
import {Goal} from '../goal/Goal';


import {MotivationSystem} from '../motivation';
import {ActionSystem} from '../action/ActionSystem';
import {GoalDrivenAction} from '../action/GoalDrivenAction';
import {ActionResult, GoalStatus, SkillSwitchHandler, InitOptions} from '../common/Types';
import {State, ActionEvents} from '../common';
import {HJGoalProvider, SSWGoalProvider} from '../goal/goalproviders';
import JiboLog = require('jibo-log');
import {DateProvider} from "./DateProvider";

// Only importing type definition
import JiboImport = require('../../../jibo'); // NOTE: only for type declaration, not runtime dependency


export {} // For type definition purposes

/**
 * @class ActionRuntime
 * @memberof jibo.action.common
 * @internal
 */
export class ActionRuntime {

    /*
     * Systems
     */
    public goals = new GoalSet(this);
    public actions = new ActionSystem(this);
    public motivations = new MotivationSystem(this);

    public events = new ActionEvents();

    /**
     * This should not be a part of the external API
     * @internal
     */
    jibo: typeof JiboImport;

    log = new JiboLog('action-system');

    skillSwitcher: SkillSwitchHandler;
    currentSkillName: string;

    current: GoalDrivenAction;

    /**
     * The dateProvider insulates us from the weirdness of the system being stuck in UTC.
     * @type {any}
     */
    dateProvider = new DateProvider(this);

    /*
     * Goal providers
     */
    private hjGoalProvider = new HJGoalProvider(this);
    private sswGoalProvider = new SSWGoalProvider(this);
    // private hjOnlyGoalProvider = new HJOnlyGoalProvider(this);

    private updateBind = this.update.bind(this);
    private updateDownSample = 0;

    private options: InitOptions;


    /**
     * Initializes and creates the polling loop
     */
    async init(options: InitOptions): Promise<any> {
        this.options = options;
        if (options.autoUpdate === undefined) {
            options.autoUpdate = true;
        }
        this.jibo = options.jibo;

        this.sswGoalProvider.init();
        this.hjGoalProvider.init();
        // Turn off hjOnly for now until it is disabled in Idle
        // this.hjOnlyGoalProvider.init();

        this.log.minLevel = 'debug';

        // On every new goal event
        this.events.goalAdded.on((goal: Goal) => {
            const state = this.createState();
            if (!goal.isEligible(state)) {
                this.log.warn(`incoming goal not currently eligible`);
                return;
            }
            // If we have an active goal
            if (this.current) {
                this.log.warn('already have an active goal');
                // If this goal is higher priority than current goal, switch
                if (goal.options.priority > this.current.goal.options.priority) {
                    this.achieveGoal(state, goal);
                }
            } else {
                // If we had no active goal, then we go ahead and pick a new one
                this.pursueNextGoal();
            }
        });

        // Subscribe to Jibo's update timer
        if (this.options.autoUpdate) {
            this.updateBind.isGlobalTimer = true;
            this.jibo.timer.on('update', this.updateBind);
        }
    }

    dispose() {
        // Unsubscribe from Jibo's update timer
        if (this.options.autoUpdate) {
            this.jibo.timer.off('update', this.updateBind);
        }

        this.sswGoalProvider.dispose();
        this.hjGoalProvider.dispose();
        // this.hjOnlyGoalProvider.dispose();
    }

    /**
     * Updates the whole behavior system
     */
    update() {
        // Down-sampled update rate
        this.updateDownSample++;
        if (this.updateDownSample === 5) {
            this.updateDownSample = 0;
            this.motivations.update();
        }
    }

    /**
     * Creates a state representation
     * @return {State}
     */
    public createState(): State {
        // TODO this needs to be tested
        return {
            time: this.dateProvider.getDate().getTime(),
            users: this.jibo.lps.identity.getPresentPersons(),
            skillName: this.currentSkillName
        };
    }


    /**
     * Pick a new goal and pursue it
     * @return {Promise<ActionResult>}
     */
    private async pursueNextGoal(): Promise<any> {
        // Choose the next goal
        const state = this.createState();
        const goal: Goal = this.goals.chooseGoal(state);
        if (goal) {
            this.log.log(`Selected goal '${goal.name}'`);
            return this.achieveGoal(state, goal);
        } else {
            this.log.log(`No new goal to select`);
        }
    }

    /**
     * Attempts to find an action to achieve a current goal. Will cancel
     * existing goal if one is currently being pursued.
     * @param {State} state
     * @param {Goal} newGoal
     * @return {Promise<ActionResult>}
     */
    private async achieveGoal(state: State, newGoal: Goal): Promise<ActionResult> {
        // If we have a currently ongoing action or goal
        if (this.current) {
            this.log.warn(`Told to achieve new goal '${newGoal.name}' so canceling current goal '${this.current.goal.name}'`);
            this.current.goal.setStatus(GoalStatus.FAILED);
            // We tell the previous action to stop and wait for it to finish
            // TODO add timeout logic
            this.log.warn(`Canceling current action '${this.current.action.name}'`);
            await this.current.action.cancel();
            if (this.current.currentRunPromise) {
                await this.current.currentRunPromise;
            }
        }

        // Choose the best action
        const action = this.actions.chooseAction(state, newGoal);
        if (action) {
            newGoal.setStatus(GoalStatus.SELECTED);
            this.current = new GoalDrivenAction(newGoal, action, this);
            return this.current.run()
                .then(result => {
                    this.log.log(`Current action'${this.current.action.name}' done: '${result}'`);
                    this.current = null;
                    // See if we need to pick another goal
                    process.nextTick(() => {
                        this.pursueNextGoal();
                    });
                    return result;
                }).catch((e) => {
                    this.current = null;
                    throw e;
                });
        }
        else {
            // Otherwise we basically return the goal
            newGoal.setStatus(GoalStatus.PENDING);
        }
    }
}
